// src/module/migrator/versions/Version0_16_0.ts
var Version0_16_0 = class extends VersionMigration {
  static {
    __name(this, "Version0_16_0");
  }
  TargetVersion = "0.16.0";
  migrateActor(actor) {
    if (actor.type !== "character" && actor.type !== "critter" && actor.type !== "vehicle")
      foundry.utils.setProperty(actor, "system.visibilityChecks.meat.hasHeat", false);
    if (actor.system.magic && "initiation" in actor.system.magic && isNaN(actor.system.magic.initiation))
      foundry.utils.setProperty(actor, "system.magic.initiation", 0);
  }
};

// src/module/migrator/versions/Version0_18_0.ts
var Version0_18_0 = class extends VersionMigration {
  static {
    __name(this, "Version0_18_0");
  }
  TargetVersion = "0.18.1";
  handlesActor(actor) {
    return Array.isArray(actor.effects);
  }
  migrateActor(actor) {
    const toDelete = actor.effects.filter((effect) => effect.origin?.includes(".Item."));
    if (toDelete.length > 0) {
      console.log(`Actor (${actor._id}). Delete these effects:`, toDelete);
      actor.effects = actor.effects.filter((effect) => !effect.origin?.includes(".Item."));
    }
  }
  migrateActiveEffect(effect) {
    effect.name ??= effect.label || "Unnamed Effect";
    delete effect.label;
  }
};

// src/module/migrator/versions/Version0_27_0.ts
var Version0_27_0 = class extends VersionMigration {
  static {
    __name(this, "Version0_27_0");
  }
  TargetVersion = "0.27.0";
  handlesActor(actor) {
    return actor.type === "spirit";
  }
  migrateActor(actor) {
    const spiritSystem = actor.system;
    if (spiritSystem.spiritType === "nocnitasa")
      spiritSystem.spiritType = "nocnitsa";
    if (spiritSystem.spiritType === "greenman")
      spiritSystem.spiritType = "green_man";
    if (spiritSystem.spiritType === "vucub")
      spiritSystem.spiritType = "vucub_caquix";
  }
};

// src/module/migrator/versions/Version0_30_0.ts
var Version0_30_0 = class extends VersionMigration {
  static {
    __name(this, "Version0_30_0");
  }
  TargetVersion = "0.30.0";
  // Handle Actor documents so they can be sanitized.
  handlesActor(_actor) {
    return true;
  }
  migrateActor(_actor) {
    if (["character", "critter", "ic", "vehicle", "sprite"].includes(_actor.type)) {
      const runningSilent = _actor.system?.matrix?.silent;
      _actor.system.matrix.running_silent = runningSilent ?? false;
    }
  }
  migrateItem(_item) {
    if (_item.data) {
      _item.system = _item.data;
      delete _item.data;
    }
    if (_item.type === "sin" && _item.system?.licenses)
      _item.system.licenses = Object.values(_item.system.licenses);
    if (_item.type === "modification" && typeof _item.system?.mount_point === "string") {
      _item.system.mount_point = _item.system.mount_point.toLowerCase();
      if (_item.system?.mount_point === "under_barrel")
        _item.system.mount_point = "under";
    }
    if (_item.system?.technology?.wireless) {
      _item.system.technology.wireless = _item.system.technology.wireless ? "online" : "offline";
    }
  }
  migrateActiveEffect(effect) {
    effect.name ??= effect.label || "Unnamed Effect";
    delete effect.label;
    const flag = effect.flags?.shadowrun5e;
    if (!flag) return;
    effect.system ??= {};
    if (flag.applyTo)
      effect.system.applyTo = flag.applyTo;
    if (flag.appliedByTest != null)
      effect.system.appliedByTest = flag.appliedByTest;
    if (flag.onlyForEquipped != null)
      effect.system.onlyForEquipped = flag.onlyForEquipped;
    if (flag.onlyForWireless != null)
      effect.system.onlyForWireless = flag.onlyForWireless;
    if (flag.onlyForItemTest != null)
      effect.system.onlyForItemTest = flag.onlyForItemTest;
    if (flag.selection_attributes)
      effect.system.selection_attributes = JSON.parse(flag.selection_attributes);
    if (flag.selection_categories)
      effect.system.selection_categories = JSON.parse(flag.selection_categories);
    if (flag.selection_limits)
      effect.system.selection_limits = JSON.parse(flag.selection_limits);
    if (flag.selection_skills)
      effect.system.selection_skills = JSON.parse(flag.selection_skills);
    if (flag.selection_tests)
      effect.system.selection_tests = JSON.parse(flag.selection_tests);
    delete effect.flags.shadowrun5e;
  }
};

// src/module/migrator/versions/Version0_30_3.ts
var Version0_30_3 = class extends VersionMigration {
  static {
    __name(this, "Version0_30_3");
  }
  TargetVersion = "0.30.3";
  handlesActor(_actor) {
    if (_actor.system.inventories) return true;
    return false;
  }
  migrateActor(_actor) {
    this._migrateNonAllInventories(_actor);
  }
  /**
   * Due to an issue with default inventory data setting showAll to true, newly created inventories, 
   * as well as default 'carried', since 0.30.0 would break display of which inventory an item belongs to.
   */
  _migrateNonAllInventories(_actor) {
    for (const inventory of Object.values(_actor.system.inventories)) {
      if (inventory.name === "All") continue;
      _actor.system.inventories[inventory.name].showAll = false;
    }
  }
};

