// src/module/apps/actorImport/itemImporter/magicImport/ComplexFormParser.ts
var ComplexFormParser = class extends Parser {
  static {
    __name(this, "ComplexFormParser");
  }
  parseType = "complex_form";
  parseItem(item, itemData) {
    const system = item.system;
    if (itemData.fv_english) {
      system.fade = Number(itemData.fv_english.substring(1)) || 0;
    }
    system.target = ["Device", "File", "Host", "Persona", "Self", "Sprite"].includes(itemData.target_english) ? itemData.target_english.toLowerCase() : "other";
    const duration = itemData.duration_english;
    if (duration === "I")
      system.duration = "immediate";
    else if (duration === "S")
      system.duration = "sustained";
    else if (duration === "P")
      system.duration = "permanent";
  }
};

