// src/module/apps/actorImport/itemImporter/weaponImport/ClipParser.ts
var ClipParser = class extends Parser {
  static {
    __name(this, "ClipParser");
  }
  parseType = "ammo";
  currentWeapon;
  constructor(currentWeapon) {
    super();
    this.currentWeapon = currentWeapon;
  }
  parseItem(item, itemData) {
    const system = item.system;
    const ammobonus = itemData.ammotype;
    system.technology.quantity = Number(itemData.count) || 1;
    system.technology.equipped = itemData.name === this.currentWeapon.currentammo;
    if (!ammobonus) return;
    system.ap = Number(ammobonus.weaponbonusap_english) || 0;
    system.accuracy = Number(ammobonus.weaponbonusacc) || 0;
    if (ammobonus.weaponbonusdamage != null) {
      system.damage = Number(/(\d+)/.exec(ammobonus.weaponbonusdamage_english)?.pop()) || 0;
      system.damageType = /S/.exec(ammobonus.weaponbonusdamage_english)?.pop() === "S" ? "stun" : "physical";
      system.element = /\(e\)/.exec(ammobonus.weaponbonusdamage_english || "")?.pop() === "(e)" ? "electricity" : "";
    }
  }
  parseCategoryFlags(item, itemData) {
    return itemData.english_name.split(":")[0];
  }
};

// src/module/apps/actorImport/itemImporter/weaponImport/WeaponParser.ts
var WeaponParser = class extends Parser {
  static {
    __name(this, "WeaponParser");
  }
  parseType = "weapon";
  getValues(val) {
    const regex = /(-?[0-9]+)(?:([0-9]+))*/g;
    const l2 = val.match(regex);
    return l2 || ["0"];
  }
  parseDamage(val) {
    const damage = {
      damage: 0,
      type: "",
      radius: 0,
      dropoff: 0
    };
    const split = val.split(" ");
    if (split.length > 0) {
      const l2 = /(\d+)(\w+)/.exec(split[0]);
      if (l2?.[1]) {
        damage.damage = parseInt(l2[1]);
      }
      if (l2?.[2]) {
        damage.type = l2[2] === "P" ? "physical" : "stun";
      }
    }
    for (let i2 = 1; i2 < split.length; i2++) {
      const l2 = /(-?\d+)(.*)/.exec(split[i2]);
      if (l2?.[2]) {
        if (l2[2].toLowerCase().includes("/m")) {
          damage.dropoff = parseInt(l2[1]);
          damage.radius = damage.damage / Math.abs(damage.dropoff);
        } else {
          damage.radius = parseInt(l2[1]);
        }
      }
    }
    return damage;
  }
  async parseWeapons(chummerChar) {
    return this.parseItems(ImportHelper.getArray(chummerChar.weapons?.weapon));
  }
  parseItem(item, itemData) {
    const system = item.system;
    const action = system.action;
    const damage = system.action.damage;
    damage.ap.base = Number(this.getValues(itemData.rawap)[0]) || 0;
    action.type = "varies";
    if (itemData.skill) {
      action.skill = itemData.skill.toLowerCase().replace(/\s/g, "_");
    } else if (itemData.category_english?.toLowerCase().includes("exotic")) {
      action.skill = itemData.category_english.toLowerCase().replace(/\s/g, "_");
    } else if (itemData.category_english?.toLowerCase().includes("laser weapons")) {
      action.skill = "exotic_ranged_weapon";
    }
    action.attribute = "agility";
    if (itemData.rawaccuracy) {
      let accuracy = itemData.rawaccuracy;
      if (itemData.rawaccuracy.includes("Physical")) {
        action.limit.attribute = "physical";
        accuracy = accuracy.replace("Physical", "").trim();
      }
      action.limit.base = Number(this.getValues(accuracy)[0]) || 0;
    }
    if (itemData.type.toLowerCase() === "melee") {
      this.handleMeleeWeapon(system, itemData);
    }
    if (itemData.type.toLowerCase() === "ranged") {
      this.handledRangedWeapon(system, itemData);
    } else if (itemData.type.toLowerCase() === "thrown") {
      system.category = "thrown";
      const ranges = ImportHelper.getArray(itemData.ranges)[0];
      if (ranges?.short && ranges.medium && ranges.long && ranges.extreme) {
        system.thrown = {
          ...system.thrown,
          ranges: {
            short: parseInt(ranges.short.split("-")[1]),
            medium: parseInt(ranges.medium.split("-")[1]),
            long: parseInt(ranges.long.split("-")[1]),
            extreme: parseInt(ranges.extreme.split("-")[1]),
            category: "manual",
            attribute: ""
          }
        };
      }
    }
    {
      const chummerDamage = this.parseDamage(itemData.damage_noammo_english);
      if (!damage.attribute) {
        damage.base = chummerDamage.damage;
        damage.type.base = chummerDamage.type;
      }
      if (chummerDamage.dropoff || chummerDamage.radius) {
        system.thrown = {
          ...system.thrown,
          blast: {
            radius: chummerDamage.radius,
            dropoff: chummerDamage.dropoff
          }
        };
      }
    }
  }
  parseCategoryFlags(item, itemData) {
    let category = "";
    if (item.system.category)
      category = item.system.category;
    const weaponCategory = itemData.category_english;
    if (!(category && weaponCategory === "gear"))
      category = weaponCategory;
    if (weaponCategory === "gear" && itemData.name_english.includes(":"))
      category = itemData.name_english.split(":")[0];
    return category;
  }
  async getEmbeddedItems(itemData) {
    return [
      ...await new AccessoryParser().parseItems(itemData.accessories?.accessory),
      ...await new ClipParser(itemData).parseItems(itemData.clips?.clip)
    ];
  }
  handleMeleeWeapon(system, itemData) {
    system.action.type = "complex";
    system.category = "melee";
    system.melee.reach = Number(itemData.rawreach) || 0;
  }
  handledRangedWeapon(system, itemData) {
    system.category = "range";
    if (system.action.skill.toLowerCase().includes("throw"))
      system.category = "thrown";
    system.ammo.current.value = Number(/\d+/.exec(itemData.ammo_english)?.[0]) || 0;
    system.ammo.current.max = system.ammo.current.value;
    if (itemData.clips?.clip) {
      const clipsArray = ImportHelper.getArray(itemData.clips.clip);
      const currentClip = clipsArray.find((clip) => clip.name === itemData.currentammo);
      system.ammo.current.value = Number(currentClip?.count) || system.ammo.current.value;
    }
    if (system.ammo.current.max) {
      const totalAmmo = Number(itemData.availableammo) || 0;
      const currentAmmo = system.ammo.current.value;
      const clipSize = system.ammo.current.max;
      const spareClips = Math.max(0, Math.floor((totalAmmo - currentAmmo) / clipSize));
      system.ammo.spare_clips.max = spareClips;
      system.ammo.spare_clips.value = spareClips;
    }
    const range = DataDefaults.createData("range_weapon");
    system.range = range;
    range.rc.base = Number(this.getValues(itemData.rawrc)[0]) || 0;
    if (itemData.mode) {
      const modes = (itemData.mode_english_noammo ?? itemData.mode_noammo).toLowerCase();
      range.modes = {
        single_shot: modes.includes("ss"),
        semi_auto: modes.includes("sa"),
        burst_fire: modes.includes("bf"),
        full_auto: modes.includes("fa")
      };
    }
    const ranges = ImportHelper.getArray(itemData.ranges)[0];
    if (ranges?.short && ranges.medium && ranges.long && ranges.extreme) {
      const rangeData = {
        short: parseInt(ranges.short.split("-")[1]),
        medium: parseInt(ranges.medium.split("-")[1]),
        long: parseInt(ranges.long.split("-")[1]),
        extreme: parseInt(ranges.extreme.split("-")[1]),
        category: "manual",
        attribute: ""
      };
      if (system.category === "range") {
        range.ranges = rangeData;
      }
      if (system.category === "thrown") {
        system.thrown = {
          ...system.thrown,
          ranges: rangeData
        };
      }
    }
  }
};

// src/module/apps/actorImport/itemImporter/ItemsParser.ts
var ItemsParser = class {
  static {
    __name(this, "ItemsParser");
  }
  /**
   * Prepares the parser by caching compendium indexes for item lookup.
   */
  async prepareParser() {
    const compendiumList = game.settings.get(SYSTEM_NAME, FLAGS.ImporterCompendiumOrder);
    Parser.compendiumCache.clear();
    for (const packId of compendiumList) {
      const pack = game.packs.get(packId);
      if (pack?.metadata.type !== "Item") continue;
      const index = await pack.getIndex({ fields: ["_id", "name", "type"] });
      Parser.compendiumCache.set(packId, index);
    }
  }
  /**
   * Parses all items from a chummer char and returns an array of the corresponding foundry items.
   * @param {*} chummerChar The chummer char holding the items
   * @param {*} importOptions Additional import option that specify what items will be imported.
   */
  async parse(chummerChar, importOptions) {
    const items = [];
    Object.freeze(chummerChar);
    await this.prepareParser();
    if (importOptions.qualities)
      items.push(...await new QualityParser().parseItems(chummerChar.qualities?.quality));
    if (importOptions.weapons)
      items.push(...await new WeaponParser().parseWeapons(chummerChar));
    if (importOptions.armor) {
      items.push(...await new ArmorParser().parseItems(chummerChar.armors?.armor));
      const otherArmors = ImportHelper.getArray(chummerChar.otherarmors?.otherarmor).map((armor) => ({
        ...armor,
        name: armor.objectname,
        name_english: armor.objectname_english,
        source: armor.sourcename
      }));
      items.push(...await new OtherArmorParser().parseItems(otherArmors));
    }
    if (importOptions.cyberware) {
      const biowares = ImportHelper.getArray(chummerChar.cyberwares?.cyberware).filter((c2) => c2.improvementsource === "Bioware");
      const cyberwares = ImportHelper.getArray(chummerChar.cyberwares?.cyberware).filter((c2) => c2.improvementsource !== "Bioware");
      items.push(...await new WareParser("bioware").parseItems(biowares));
      items.push(...await new WareParser("cyberware").parseItems(cyberwares));
    }
    if (importOptions.powers)
      items.push(...await new PowerParser().parseItems(chummerChar.powers?.power));
    if (importOptions.spells && chummerChar.spells?.spell) {
      const rituals = ImportHelper.getArray(chummerChar.spells.spell).filter((s2) => s2.category_english === "Rituals" && s2.alchemy !== "True");
      const spells = ImportHelper.getArray(chummerChar.spells.spell).filter((s2) => s2.category_english !== "Rituals" && s2.alchemy !== "True");
      items.push(...await new SpellParser().parseItems(spells));
      items.push(...await new RitualParser().parseItems(rituals));
    }
    if (importOptions.spells && chummerChar.complexforms?.complexform) {
      items.push(...await new ComplexFormParser().parseItems(ImportHelper.getArray(chummerChar.complexforms.complexform)));
    }
    if (importOptions.contacts)
      items.push(...await new ContactParser().parseItems(chummerChar.contacts?.contact));
    if (importOptions.lifestyles)
      items.push(...await new LifestyleParser().parseItems(chummerChar.lifestyles?.lifestyle));
    if (importOptions.metamagics) {
      const metamagics = ImportHelper.getArray(chummerChar.metamagics?.metamagic).filter((meta) => meta.improvementsource === "Metamagic");
      const echoes = ImportHelper.getArray(chummerChar.metamagics?.metamagic).filter((meta) => meta.improvementsource === "Echo");
      items.push(...await new SimpleParser("metamagic").parseItems(metamagics));
      items.push(...await new SimpleParser("echo").parseItems(echoes));
    }
    if (importOptions.powers)
      items.push(...await new CritterPowerParser().parseItems(chummerChar.critterpowers?.critterpower));
    if (importOptions.equipment)
      items.push(...await new GearsParser().parseItems(chummerChar.gears?.gear));
    return items;
  }
};

// src/module/apps/actorImport/itemImporter/vehicleImport/MountedWeaponParser.ts
