// src/module/apps/itemImport/parser/Parser.ts
var Parser3 = class {
  static {
    __name(this, "Parser");
  }
  isActor() {
    return Object.keys(CONFIG.Actor.dataModels).includes(this.parseType);
  }
  getBonus(jsonData) {
    return "bonus" in jsonData ? jsonData.bonus : void 0;
  }
  async getItems(jsonData) {
    return [];
  }
  getSystem(jsonData) {
    return this.getBaseSystem();
  }
  getSanitizedSystem(jsonData) {
    const system = this.getSystem(jsonData);
    const schema = this.isActor() ? CONFIG.Actor.dataModels[this.parseType].schema : CONFIG.Item.dataModels[this.parseType].schema;
    const correctionLogs = Sanitizer.sanitize(schema, system);
    if (correctionLogs) {
      console.warn(
        `Document Sanitized on Import:
Name: ${jsonData.name._TEXT};
Type: ${this.isActor() ? "Actor" : "Item"}; SubType: ${this.parseType};
`
      );
      console.table(correctionLogs);
    }
    return system;
  }
  async Parse(jsonData, compendiumKey) {
    const itemPromise = this.getItems(jsonData);
    const entity = {
      img: void 0,
      name: ImportHelper.getArray(jsonData.translate)[0]?._TEXT ?? jsonData.name._TEXT,
      type: this.parseType,
      system: this.getSanitizedSystem(jsonData),
      folder: (await this.getFolder(jsonData, compendiumKey)).id
    };
    const system = entity.system;
    if ("technology" in system && system.technology)
      this.setTechnology(system.technology, jsonData);
    this.setImporterFlags(entity, jsonData);
    entity.img = IconAssign.iconAssign(entity);
    BonusHelper.addBonus(entity, this.getBonus(jsonData));
    if (jsonData.page && jsonData.source) {
      const page = ImportHelper.getArray(jsonData.altpage)[0]?._TEXT ?? jsonData.page._TEXT;
      const source = jsonData.source._TEXT;
      system.description.source = `${source} ${page}`;
    }
    if (this.isActor())
      entity.items = await itemPromise;
    else
      entity.flags = { shadowrun5e: { embeddedItems: await itemPromise } };
    return entity;
  }
  setTechnology(technology, jsonData) {
    technology.availability = "avail" in jsonData && jsonData.avail ? jsonData.avail._TEXT || "" : "";
    technology.cost = "cost" in jsonData && jsonData.cost ? Number(jsonData.cost._TEXT) || 0 : 0;
    technology.rating = "rating" in jsonData && jsonData.rating ? Number(jsonData.rating._TEXT) || 0 : 0;
    technology.conceal.base = "conceal" in jsonData && jsonData.conceal ? Number(jsonData.conceal._TEXT) || 0 : 0;
  }
  setImporterFlags(entity, jsonData) {
    const category = "category" in jsonData ? jsonData.category?._TEXT || "" : "";
    entity.system.importFlags = {
      category,
      isFreshImport: true,
      name: jsonData.name._TEXT,
      sourceid: jsonData.id._TEXT
    };
  }
  getBaseSystem(createData = {}) {
    return DataDefaults.baseSystemData(this.parseType, createData);
  }
};

// src/module/apps/itemImport/parser/misc/ActionParser.ts
var DICE_POOL_SEPARATOR = "v.";
var ACTION_PREFIX = "Action:";
var THRESHOLD_PREFIX = "Threshold:";
var ActionParser = class extends Parser3 {
  static {
    __name(this, "ActionParser");
  }
  parseType = "action";
  attrs = Object.keys(SR5.attributes);
  limits = Object.keys(SR5.limits);
  skills = Object.keys(SR5.activeSkills);
  storedActions = {};
  systemActions;
  constructor(matrixActions) {
    super();
    this.systemActions = matrixActions;
  }
  searchSystemActionByName(name) {
    const queryName = name.replace(/\s*\(.*?\)\s*/g, "").replace(/\s*IC\s*$/i, "").trim();
    return this.systemActions.find((ma) => ma.name === queryName);
  }
  // Parse the action and set the image if a system action is found
  async Parse(jsonData, compendiumKey) {
    const item = await super.Parse(jsonData, compendiumKey);
    const systemAction = this.searchSystemActionByName(jsonData.name._TEXT);
    if (systemAction) item.img = systemAction.img;
    return item;
  }
  getSystem(jsonData) {
    const system = this.getBaseSystem();
    const { action, description } = system;
    const systemAction = this.searchSystemActionByName(jsonData.name._TEXT);
    if (systemAction) {
      foundry.utils.mergeObject(system, systemAction.system, { insertKeys: false, insertValues: false });
      description.value = jsonData.test?.bonusstring?._TEXT ?? "";
      return system;
    }
    action.type = jsonData.type._TEXT.toLowerCase();
    action.extended = jsonData.type._TEXT === "Extended";
    description.value = jsonData.test?.bonusstring?._TEXT ?? "";
    if (jsonData.initiativecost?._TEXT)
      action.initiative_mod = -Number(jsonData.initiativecost._TEXT);
    if (jsonData.test) {
      const [dicePoolStr, opposedDicePoolStr] = jsonData.test.dice._TEXT.split(DICE_POOL_SEPARATOR);
      this.parseDicePool(system, action, dicePoolStr);
      if (opposedDicePoolStr)
        this.parseOpposedPool(system, action, opposedDicePoolStr);
      if (jsonData.test.limit?._TEXT) {
        const limit = ImportHelper.formatAsSlug(jsonData.test.limit._TEXT).replaceAll("-", "_");
        action.limit.attribute = this.limits.find((l2) => limit.includes(l2)) || "";
      }
    }
    this.setTestAction(action, jsonData);
    if (jsonData.test?.bonusstring?._TEXT)
      this.handleSpecial(action, jsonData.test.bonusstring._TEXT);
    this.storedActions[jsonData.name._TEXT] = action;
    return system;
  }
  handleSpecial(action, bonusstring) {
    const marks = Number(/Requires\s+(\d+)\s+marks?/i.exec(bonusstring)?.[1]);
    if (marks)
      action.category.matrix.marks = marks;
    if (bonusstring.includes("resist {Icon: Attack}")) {
      action.damage.type.base = "matrix";
      action.damage.attribute = "attack";
      action.opposed.resist.test = "MatrixDefenseTest";
      if (bonusstring.toLowerCase().includes("biofeedback")) {
        action.opposed.resist.test = "BiofeedbackResistTest";
        if (bonusstring.toLowerCase().includes("stun"))
          action.damage.biofeedback = "stun";
      }
    }
    if (bonusstring.toLowerCase().includes("resist fading"))
      action.followed.test = "FadeTest";
  }
  /**
   * Parses a dice pool string and applies its components (attributes, skill, modifier) to a target object.
   */
  parseDicePool(system, target, dicePoolStr) {
    if (dicePoolStr === "None") return;
    const components = [...dicePoolStr.matchAll(/\{([^{}]*(?:\{[^{}]*\}[^{}]*)*)\}/g)].map((m2) => m2[1]);
    if (components[0]?.includes(ACTION_PREFIX) || this.storedActions[components[0]]) {
      const actionName = components[0].replace(ACTION_PREFIX, "").trim();
      const otherAction = this.storedActions[actionName];
      if (otherAction) {
        foundry.utils.mergeObject(target, otherAction, { insertKeys: false, insertValues: false });
      } else {
        console.warn(`Action reference not found: ${actionName}`);
      }
      return;
    }
    if (components[0]) target.attribute = Constants.attributeTable[components[0]];
    if (components[1]) target.attribute2 = Constants.attributeTable[components[1]];
    if (dicePoolStr.trim() === "2 * {Icon: Rating}") {
      target.attribute = "rating";
      target.attribute2 = "rating";
    }
    if (components[0] && !target.attribute) {
      const attrSlug = ImportHelper.formatAsSlug(components[0]).replaceAll("-", "_");
      target.attribute = this.attrs.find((a2) => attrSlug.includes(a2)) || "";
    }
    if (components[1] && !target.attribute2) {
      const attrSlug = ImportHelper.formatAsSlug(components[1]).replaceAll("-", "_");
      target.attribute2 = this.attrs.find((a2) => attrSlug.includes(a2)) || "";
    }
    if (components[1] && !target.attribute2) {
      const skillSlug = ImportHelper.formatAsSlug(components[1]).replaceAll("-", "_");
      target.skill = this.skills.find((s2) => skillSlug.includes(s2)) || "";
    }
    if (!isNaN(Number(components[0])))
      target.mod = Number(components[0]);
    const modifier = [...dicePoolStr.replace("2 *", "").matchAll(/([+-]?\s*\d+)/g)].map((m2) => Number(m2[1].replaceAll(/\s+/g, ""))).reduce((acc, curr) => acc + curr, 0);
    if (modifier)
      target.mod += modifier;
    if (!target.attribute || !(target.attribute2 || target.skill)) {
      if (!target.attribute && components[0])
        this.addException(system.description, components[0]);
      if (!(target.attribute2 || target.skill) && components[1])
        this.addException(system.description, components[1]);
    }
    for (const comp of components.slice(2))
      this.addException(system.description, comp);
  }
  addException(description, exception) {
    if (exception.includes("Improvement Value:")) return;
    description.value += `

[Cannot automate pool: {${exception}}]`;
  }
  /**
   * Parses the opposed part of a test string.
   */
  parseOpposedPool(system, action, opposedDicePoolStr) {
    const components = [...opposedDicePoolStr.matchAll(/\{([^}]+)\}/g)].map((m2) => m2[1]);
    const { opposed, threshold } = action;
    action.opposed.test = "OpposedTest";
    if (components[0]?.includes(THRESHOLD_PREFIX)) {
      threshold.base = Number(components[0].replace(THRESHOLD_PREFIX, "").trim()) || 0;
    } else {
      this.parseDicePool(system, opposed, opposedDicePoolStr);
    }
  }
  /**
   * Sets the final 'test' property on the action based on its name, category, or skill.
   */
  setTestAction(action, jsonData) {
    const name = jsonData.name._TEXT;
    const category = jsonData.category?._TEXT;
    const testMap = {
      "Melee Attack": "MeleeAttackTest",
      "Melee Defense": "PhysicalDefenseTest",
      "Ranged Defense": "PhysicalDefenseTest",
      "Suppressive Fire Defense": "PhysicalDefenseTest",
      "Use Skill": "SkillTest"
    };
    if (name.includes("Reckless Spellcasting")) {
      action.followed.mod = 3;
    }
    if (testMap[name]) {
      action.test = testMap[name];
    } else if (name.includes("Spell Defense")) {
      action.test = "CombatSpellDefenseTest";
    } else if (action.skill === "spellcasting") {
      action.test = "SpellCastingTest";
      action.followed.test = "DrainTest";
    } else if (name.includes("Brute Force")) {
      action.test = "BruteForceTest";
      action.opposed.test = "OpposedBruteForceTest";
      action.opposed.resist.test = "MatrixResistTest";
    } else if (name.includes("Hack on the Fly")) {
      action.test = "HackOnTheFlyTest";
      action.opposed.test = "OpposedHackOnTheFlyTest";
    } else if (action.skill === "throwing_weapon") {
      action.test = "ThrownAttackTest";
    } else if (action.skill === "summoning") {
      action.test = "SummonSpiritTest";
      action.followed.test = "DrainTest";
      action.opposed.test = "OpposedSummonSpiritTest";
    } else if (action.skill === "compiling") {
      action.test = "CompileSpriteTest";
      action.followed.test = "FadeTest";
      action.opposed.test = "OpposedCompileSpriteTest";
    } else if (jsonData.test?.dice._TEXT.includes("Ranged Defense")) {
      action.test = "RangedAttackTest";
    } else if (category === "Matrix" && name.includes("Defense")) {
      action.test = "MatrixDefenseTest";
    } else if (category === "Matrix" || action.opposed.test === "MatrixDefenseTest") {
      action.test = "MatrixTest";
      if (action.test === "MatrixTest" && action.opposed.test === "OpposedTest")
        action.opposed.test = "MatrixDefenseTest";
    }
    const cls = TestCreator._getTestClass(action.test);
    if (cls) {
      try {
        const testCls = new cls(TestCreator._minimalTestData());
        action.categories = testCls.testCategories;
        action.modifiers = testCls.testModifiers;
      } catch (error) {
        console.error("Error creating test class:", error);
      }
    }
  }
  async getFolder(jsonData, compendiumKey) {
    const isMatrixAction = this.searchSystemActionByName(jsonData.name._TEXT) !== void 0 || (this.storedActions[jsonData.name._TEXT]?.test?.includes("Matrix") ?? false);
    const matrixLabel = game.i18n.localize("SR5.Labels.ActorSheet.Matrix");
    const rootFolder = game.i18n.localize("TYPES.Item.action") + (isMatrixAction ? ` (${matrixLabel})` : "");
    const subFolder = jsonData.type?._TEXT || "Unknown";
    return ImportHelper.getFolder(compendiumKey, rootFolder, subFolder);
  }
};

