// src/module/apps/itemImport/parser/gear/AmmoParser.ts
var AmmoParser2 = class extends Parser3 {
  static {
    __name(this, "AmmoParser");
  }
  parseType = "ammo";
  categories;
  constructor(categories) {
    super();
    this.categories = categories;
  }
  getSystem(jsonData) {
    const system = this.getBaseSystem();
    const bonusData = jsonData.weaponbonus;
    if (bonusData) {
      system.ap = Number(bonusData.ap?._TEXT) || 0;
      system.damage = Number(bonusData.damage?._TEXT) || 0;
      const damageType = bonusData.damagetype?._TEXT ?? "";
      if (damageType.includes("S"))
        system.damageType = "stun";
      else if (damageType.includes("M"))
        system.damageType = "matrix";
      else
        system.damageType = "physical";
    }
    return system;
  }
  setImporterFlags(entity, jsonData) {
    super.setImporterFlags(entity, jsonData);
    if (entity.system.importFlags.category === "Ammunition") {
      entity.system.importFlags.category = entity.name.split(":")[0].trim();
    }
  }
  async Parse(jsonData, compendiumKey) {
    const item = await super.Parse(jsonData, compendiumKey);
    const system = item.system;
    if (jsonData.addweapon?._TEXT) {
      const weaponName = jsonData.addweapon._TEXT;
      const foundWeapon = (await ImportHelper.findItems("Weapon", [weaponName]))[0];
      if (foundWeapon && "action" in foundWeapon.system) {
        const weaponData = foundWeapon.system;
        system.damageType = weaponData.action.damage.type.base;
        system.element = weaponData.action.damage.element.base;
        system.damage = weaponData.action.damage.value;
        system.ap = weaponData.action.damage.ap.value;
        system.blast = weaponData.thrown.blast;
      } else if (!foundWeapon) {
        console.warn(`[Weapon Missing (Ammo)]
Ammo: ${item.name}
Weapon: ${weaponName}`);
      }
    }
    return item;
  }
  async getFolder(jsonData, compendiumKey) {
    const categoryData = jsonData.category._TEXT;
    const rootFolder = game.i18n.localize("SR5.ItemTypes.Ammo");
    const folderName = ImportHelper.getTranslatedCategory("gear", categoryData);
    let specFolder;
    if (categoryData === "Ammunition") {
      specFolder = "Misc";
      const splitName = ImportHelper.getTranslatedCategory("gear", jsonData.name._TEXT).split(":");
      if (splitName.length > 1)
        specFolder = splitName[0].trim();
    }
    return ImportHelper.getFolder(compendiumKey, rootFolder, folderName, specFolder);
  }
};

