// src/module/apps/itemImport/parser/spell/SpellParserBase.ts
var SpellParserBase = class extends Parser3 {
  static {
    __name(this, "SpellParserBase");
  }
  parseType = "spell";
  getSystem(jsonData) {
    const system = this.getBaseSystem();
    system.action.type = "varies";
    system.action.attribute = "magic";
    system.action.skill = "spellcasting";
    system.category = jsonData.category._TEXT.toLowerCase();
    if (system.category.endsWith("s"))
      system.category = system.category.slice(0, -1);
    const damage = jsonData.damage._TEXT;
    if (damage === "P") {
      system.action.damage.type.base = "physical";
      system.action.damage.type.value = "physical";
    } else if (damage === "S") {
      system.action.damage.type.base = "stun";
      system.action.damage.type.value = "stun";
    }
    const duration = jsonData.duration._TEXT;
    if (duration === "I")
      system.duration = "instant";
    else if (duration === "S")
      system.duration = "sustained";
    else if (duration === "P")
      system.duration = "permanent";
    const drain = jsonData.dv._TEXT;
    if (drain.includes("+") || drain.includes("-"))
      system.drain = parseInt(drain.substring(1, drain.length));
    const range = jsonData.range._TEXT;
    if (range === "T")
      system.range = "touch";
    else if (range === "LOS")
      system.range = "los";
    else if (range === "LOS (A)")
      system.range = "los_a";
    const type = jsonData.type._TEXT;
    if (type === "P")
      system.type = "physical";
    else if (type === "M")
      system.type = "mana";
    return system;
  }
  async getFolder(jsonData, compendiumKey) {
    const folderName = ImportHelper.getTranslatedCategory("spells", jsonData.category._TEXT);
    return ImportHelper.getFolder(compendiumKey, folderName);
  }
};

