// src/module/apps/itemImport/parser/spell/IllusionSpellParser.ts
var IllusionSpellParser = class extends SpellParserBase {
  static {
    __name(this, "IllusionSpellParser");
  }
  getSystem(jsonData) {
    const system = super.getSystem(jsonData);
    if (system.type === "mana") {
      system.action.opposed.type = "custom";
      system.action.opposed.attribute = "logic";
      system.action.opposed.attribute2 = "willpower";
    } else if (system.type === "physical") {
      system.action.opposed.type = "custom";
      system.action.opposed.attribute = "intuition";
      system.action.opposed.attribute2 = "logic";
    }
    return system;
  }
};

// src/module/apps/itemImport/parser/spell/DetectionSpellParser.ts
var DetectionSpellParser = class extends SpellParserBase {
  static {
    __name(this, "DetectionSpellParser");
  }
  getSystem(jsonData) {
    const system = super.getSystem(jsonData);
    const descriptor = jsonData.descriptor ? jsonData.descriptor._TEXT : "";
    system.detection.passive = descriptor.includes("Passive");
    if (!system.detection.passive) {
      system.action.opposed.type = "custom";
      system.action.opposed.attribute = "willpower";
      system.action.opposed.attribute2 = "logic";
    }
    system.detection.extended = descriptor.includes("Extended");
    if (descriptor.includes("Psychic"))
      system.detection.type = "psychic";
    else if (descriptor.includes("Directional"))
      system.detection.type = "directional";
    else if (descriptor.includes("Area"))
      system.detection.type = "area";
    return system;
  }
};

